var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"1년 뒤.","JPN":"1年後。","ENG":"1 year later.","TWN":"1年後","THA":"1 ปีต่อมา","VTN":"1 năm sau.","SCN":"1年后。","DEU":"1 Jahr später.","FRA":"1 an plus tard"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"노르드나빅 남부. 셔우드 외성. \\n왕립 국경수비대 텃밭.","JPN":"ノルドナビックの南部。シャーウッド外郭。\\n王立国境守備隊の畑。","ENG":"[[","TWN":"諾爾德萊比南方 休烏特外城 \\n皇家國境護衛隊菜園","THA":"ตอนใต้ของนอร์ดเนวิก ปราสาทชั้นนอกเชอร์วูด\\nสวนผักขององครักษ์หลวงพิทักษ์ชายแดน","VTN":"Phía Nam Nordnavik. Bên ngoài lâu đài Sherwood. \\nVườn rau của Cảnh vệ Biên phòng Hoàng gia.","SCN":"诺德纳维克南部，舍伍德外城。\\n皇家边境护卫队菜园。","DEU":"Süd-Nordnavik. Außenburg Sherwood.\\nGemüsegarten des Königlichen Grenzschutzes.","FRA":"Sud de Nordnavik, fort Sherwood\\nPotager des garde-frontières royaux"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"상태는 어떻지?","JPN":"状況はどうだ？","ENG":"How are things looking?","TWN":"狀態如何？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"평소보다 크네요. 이번에 만든 습도 조절기가 잘 듣나 봐요.","JPN":"いつもより大きいですね。今度作った湿度調節器がよく効いたみたいです。","ENG":"They're bigger than usual. I guess the humidifier we made seems to be working well.","TWN":"比平時還大呢，看來這次做的溼度調節器效果很不錯。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"수확 주기도 점점 빨라지겠군. 창고를 한 번 더 증축해야겠어.","JPN":"収穫サイクルもだんだん早まりそうだな。もう一度倉庫を増築しないといけない。","ENG":"Then our harvest cycle should also shorten. We'll need to expand the warehouse yet again.","TWN":"收成的週期也越來越短，需要再擴建倉庫。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"헤헤, 하지만 실컷 따 둬도 싹이 자라면 못 먹는 게 감자 아니겠어요?","JPN":"へへ、でもいっぱい収穫しておいても、ジャガイモって芽が生えると食べられないじゃないですか。","ENG":"Heh heh! Just hope the potatoes are still edible after they start sprouting.","TWN":"嘿嘿，可是就算全部收割起來，但馬鈴薯發芽的話就不能吃咧？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"GUARD_BORDER_NULL_A","text":{"KOREA":"이런 좋은 날씨에 온종일 감자나 캐고 있어야 하다니…….","JPN":"こんないい天気に一日中ジャガイモを収穫しないといけないなんて……","ENG":"Can't believe I'm digging for potatoes on a fine day like this...","TWN":"天氣這麼好，我們竟然整天都在挖挖馬鈴薯……"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":null,"R":{"char_id":"GUARD_BORDER_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"GUARD_BORDER_NULL_B","text":{"KOREA":"그러게. 오늘 같은 날은 낚시하기 딱 좋은데 말이지.","JPN":"そうだなぁ。今日は釣り日和なんだけどなぁ。","ENG":"I feel ya. This weather's perfect for going fishing.","TWN":"就是說，今天的天氣超適合釣魚的。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"GUARD_BORDER_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_BORDER_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"이봐, 불만쟁이들. 소쿠리가 제일 가벼운 녀석은 오늘 나랑 같이 야간 정비다.","JPN":"おい、そこのクレーマーども。籠が一番軽いやつは今日俺一緒に徹夜整備だ。","ENG":"Hey, whiners. The person with the lightest basket today will join me tonight for night duty.","TWN":"喂，你們這些抱怨鬼，籃子最輕的人今天要和我一起加班維修機器喔！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GUARD_BORDER_NULL_A","text":{"KOREA":"잘못 걸렸다간 흙이 아니라 기름칠을 실컷 하겠군.","JPN":"下手したら土じゃなくてオイルまみれになるな。","ENG":"Guess one of us will be digging all day and oiling machines all night.","TWN":"被逮到的話，身上沾到的可能不是泥巴而是機油。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"GUARD_BORDER_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_BORDER_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GUARD_BORDER_NULL_B","text":{"KOREA":"어이, 잠깐! 그 큰 감자는 내가 캔 거라고!","JPN":"おい、待てよ！　その大きいジャガイモは俺が掘ったやつだぞ！","ENG":"H-hey! That big tater's mine!","TWN":"喂，等一下！那顆大的馬鈴薯是我挖的！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"GUARD_BORDER_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_BORDER_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"수확 때마다 병사들과 함께 와 줘서 고맙습니다, 대장님.","JPN":"収穫する時にいつも兵士たちと来てくださってありがとうございます、隊長。","ENG":"Captain, thank you for always volunteering with your men to harvest crops.","TWN":"隊長，每次收成時你都和士兵們一起來幫忙，真是謝謝你。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"그런 의미로, 이번 수확의 절반은 가져가시죠.","JPN":"感謝の意味で、今回の収穫の半分はお持ち帰りください。","ENG":"Please, take half of today's yield as a token of my gratitude.","TWN":"這次的收成一半歸你吧，就當作是謝禮。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그렇게 많이 줘도 괜찮겠습니까?\xA0","JPN":"そんなにもらってもいいんですか？\xA0","ENG":"Are you sure it's okay to give us so much?\xA0","TWN":"給我這麼多沒關係嗎？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"지휘관이 만들어 준 장치 덕분에 수확량이 크게 늘었습니다.","JPN":"指揮官が作ってくれた装置のおかげで、収穫量が大きく増えました。","ENG":"Our potato yields have never been better after Commander made that device.","TWN":"都是拜指揮官做的裝置所賜，收成才能增加這麼多。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"이제 식량을 아끼려다 누가 굶을 걱정도 많이 덜었죠.","JPN":"もう食糧を節約するために誰かが飢える心配をすることも減りました。","ENG":"Now we don’t have to worry about anyone starving.","TWN":"現在也不用因為要現在節省糧食，而擔心誰會挨餓。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};